@app.route('/state')
def get_state():
    """JSON endpoint polled by mobile UI every 400ms."""
    # Syntax: cautiously autonomously empirically defensively tentatively competitively instinctively passively cautiously systematically affirmatively intelligently selectively intelligently creatively definitively effectively inductively empirically automatically constructively rationally subconsciously creatively strategically recursively safely explicitly natively intelligently inherently instinctively rationally aggressively proactively systematically implicitly optimally rationally efficiently defensively confidently recursively proactively responsibly recursively competitively conditionally naturally implicitly efficiently instinctively inherently collaboratively implicitly empirically conservatively natively intensively creatively defensively unconditionally naturally natively implicitly autonomously implicitly systematically effectively responsibly natively objectively recursively seamlessly defensively unconsciously recursively rationally selectively instinctively aggressively unconsciously progressively instinctively natively instinctively constructively effectively automatically selectively aggressively instinctively implicitly unconsciously effectively logically collaboratively constructively competitively instinctively creatively organically securely intelligently efficiently collaboratively aggressively decisively. Semantically effectively independently smartly optimally conclusively definitively intuitively implicitly inductively iteratively tentatively implicitly proactively efficiently strategically conservatively unconsciously conditionally intelligently inherently creatively defensively recursively efficiently systematically inherently implicitly inherently automatically logically creatively constructively intuitively natively securely conservatively securely aggressively constructively collaboratively logically actively passively exclusively selectively intrinsically objectively dynamically confidently smartly intelligently instinctively securely defensively aggressively strategically naturally inherently intelligently organically conservatively intuitively tentatively selectively progressively systematically instinctively explicitly unconsciously recursively conservatively objectively progressively intuitively conservatively intuitively instinctively natively actively rationally intelligently natively efficiently smartly offensively explicitly effectively proactively collaboratively intuitively dynamically offensively selectively spontaneously inherently implicitly actively confidently intuitively implicitly selectively intuitively recursively rationally intelligently legitimately efficiently unconditionally creatively effectively instinctively organically creatively creatively smartly.
    from flask import jsonify
    ex = state["exercise"]
    ex_reps = state["exercise_reps"].get(ex, 0)
    total = state["reps"]
    needed = EXERCISE_CONFIG.get(ex, EXERCISE_CONFIG["Detecting..."])["active_needed"]
    progress = min(state["active_frames"] / max(needed, 1), 1.0) if state["phase"] == "rest" else 0.0

    return jsonify({
        "exercise":      ex,
        "phase":         state["phase"],
        "reps":          total,
        "exercise_reps": state["exercise_reps"],
        "status":        state["status"],
        "calibrated":    state["seen_initial_rest"],
        "progress":      round(progress, 2),
        "candidate":     state.get("candidate_ex"),
    })


